query listPropertiesWithImages($limit: Int, $page: Int) {
  listPropertiesWithImages(limit: $limit, page: $page) {
    success
    count
    data {
      id
      title
    }
  }
}

query listPropertiesWithImages($limit: Int, $page: Int, $minPrice: Float, $maxPrice: Float, $bedrooms: Int) {
  listPropertiesWithImages(limit: $limit, page: $page, minPrice: $minPrice, maxPrice: $maxPrice, bedrooms: $bedrooms) {
    success
    count
    nextToken
    approvedCount
    pendingCount
    data {
      id
      title
      price
      bedrooms
      images {
        url
        label
      }
    }
    pagination {
      current_page
      has_next_page
      has_prev_page
      limit
      total_count
      total_pages
    }
  }
}
